/* Compatibility shims for embedded action code */
#ifndef ECHO
#define ECHO fwrite(yytext, 1, yyleng, stdout)
#endif

static int input(void) { if (seulex_action_pos < seulex_n) return (unsigned char)seulex_buf[seulex_action_pos++]; return 0; }


/* User code section */

int yywrap(void)
{
	return 1;
}

void error(const char *msg) {
    fprintf(stderr, "error: %s\n", msg);
    exit(1);
}

void comment(void)
{
	char c, prev = 0;   /* 存放当前和前一个字符 */
  
	while ((c = input()) != 0)      /* (EOF maps to 0) */
	{
		if (c == '/' && prev == '*')     /* 读到了注释的右边界 */
			return;
		prev = c;
	}
	error("unterminated comment");
}


int column = 0;

void count(void) /*记录当前位于第几列*/
{
	int i;

	for (i = 0; yytext[i] != '\0'; i++)         /* '\0'表示结束符或空格符*/
		if (yytext[i] == '\n')
			column = 0;
		else if (yytext[i] == '\t')
			column += 8 - (column % 8);
		else
			column++;

	ECHO;
}


int check_type(void)
{
/*
* pseudo code --- this is what it should check
*
*	if (yytext == type_name)
*		return TYPE_NAME;
*
*	return IDENTIFIER;
*/

/*
*	it actually will only return IDENTIFIER
*/

	return IDENTIFIER;
}

